"""Evaluate lexicon-based sentiment analyzers (TextBlob and VADER) on the provided test set.
Usage (from repository root): python project\evaluate_lexicons.py
Outputs: - prints metrics (accuracy, precision, recall, f1) per tool - saves CSV with predictions to project/predictions.csv
Assumptions: - test CSV is at ../src/Tweets_EN_sentiment_test.csv (relative to this script) - labels are 'pos' and 'neg' - neutral VADER outputs are mapped to 'pos' to keep binary labels (assumption) """
import os import sys import pandas as pd from sklearn.metrics import accuracy_score, precision_score, recall_score, f1_score, confusion_matrix
# Try to import analyzers; if missing, will show helpful error try: from textblob import TextBlob except Exception as e: TextBlob = None
try: from vaderSentiment.vaderSentiment import SentimentIntensityAnalyzer except Exception as e: SentimentIntensityAnalyzer = None
def safe_text(s): if pd.isna(s): return "" return str(s)
def tb_predict(text): # TextBlob polarity in [-1,1] blob = TextBlob(text) pol = blob.sentiment.polarity return 'pos' if pol > 0 else 'neg'
def vader_predict(analyzer, text): scores = analyzer.polarity_scores(text) c = scores['compound'] # VADER recommended thresholds: >=0.05 positive, <=-0.05 negative, otherwise neutral if c >= 0.05: return 'pos' elif c <= -0.05: return 'neg' else: # Map neutral to 'pos' to keep binary labels (assumption). Alternative: map to neg. return 'pos'
def metrics(y_true, y_pred): acc = accuracy_score(y_true, y_pred) prec = precision_score(y_true, y_pred, pos_label='pos') rec = recall_score(y_true, y_pred, pos_label='pos') f1 = f1_score(y_true, y_pred, pos_label='pos') cm = confusion_matrix(y_true, y_pred, labels=['pos', 'neg']) return { 'accuracy': acc, 'precision_pos': prec, 'recall_pos': rec, 'f1_pos': f1, 'confusion_matrix': cm.tolist() }
def main(): script_dir = os.path.dirname(os.path.abspath(__file__)) test_path = os.path.normpath(os.path.join(script_dir, '..', 'src', 'Tweets_EN_sentiment_test.csv'))
if not os.path.exists(test_path): print(f"Test CSV not found at expected path: {test_path}") sys.exit(1)
df = pd.read_csv(test_path) # expect columns: tweet, text, class if 'text' not in df.columns or 'class' not in df.columns: print("CSV does not contain required 'text' and 'class' columns. Columns found:", df.columns.tolist()) sys.exit(1)
df['text_clean'] = df['text'].apply(safe_text) y_true = df['class'].astype(str).tolist()
results = {}
if TextBlob is not None: df['pred_textblob'] = df['text_clean'].apply(tb_predict) mb = metrics(y_true, df['pred_textblob'].tolist()) results['TextBlob'] = mb else: print("TextBlob is not installed or failed to import. Skipping TextBlob.")
if SentimentIntensityAnalyzer is not None: analyzer = SentimentIntensityAnalyzer() df['pred_vader'] = df['text_clean'].apply(lambda t: vader_predict(analyzer, t)) mv = metrics(y_true, df['pred_vader'].tolist()) results['VADER'] = mv else: print("vaderSentiment is not installed or failed to import. Skipping VADER.")
# Save predictions out_path = os.path.join(script_dir, 'predictions.csv') save_cols = ['tweet', 'text', 'class'] if 'pred_textblob' in df.columns: save_cols.append('pred_textblob') if 'pred_vader' in df.columns: save_cols.append('pred_vader') df.to_csv(out_path, index=False, columns=save_cols)
# Print report print('\nEvaluation report:') for tool, r in results.items(): print(f"\n{tool} metrics:") print(f" Accuracy: {r['accuracy']:.4f}") print(f" Precision (pos): {r['precision_pos']:.4f}") print(f" Recall (pos): {r['recall_pos']:.4f}") print(f" F1 (pos): {r['f1_pos']:.4f}") print(f" Confusion matrix (rows=true [pos,neg], cols=pred [pos,neg]): {r['confusion_matrix']}")
print(f"\nPredictions saved to: {out_path}")
if __name__ == '__main__': main()
